                    <img src={heroImage} alt="gambar hero" className="w-md-50 w-100" />
                    <p>
                        Lorem ipsum dolor sit amet, consectetur adipisicing elit. Nulla molestiae, alias vero aliquam nobis
                        distinctio iure minima ab inventore veritatis itaque aut incidunt cumque molestias ullam exercitationem. Nesciunt, corporis error.
                    </p>
                </div>
            </div>
        </div>
    )
}
